using sv_29fb1a693b474e1db6cd503ab98e3853.Models;

namespace sv_29fb1a693b474e1db6cd503ab98e3853.Services;

public class InMemorySettingsService : ISettingsService
{
    private UserProfile _profile = new(
        "Jane Doe",
        "jane.doe@example.com",
        "https://i.pravatar.cc/150?img=47",
        "Software engineer who loves building great user experiences.");

    private NotificationPrefs _notificationPrefs = new(
        EmailNotifications: true,
        PushNotifications: true,
        WeeklyDigest: false,
        MutedChannels: ["#random", "#off-topic", "#announcements", "#general", "#engineering"]);

    private SecuritySettings _security = new(
        TwoFactorEnabled: false,
        LastPasswordChange: DateTime.UtcNow.AddDays(-45),
        Sessions:
        [
            new("sess-1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
            new("sess-2", "Safari on iPhone", "New York, US", DateTime.UtcNow.AddHours(-3)),
            new("sess-3", "Firefox on Linux", "London, UK", DateTime.UtcNow.AddDays(-2)),
        ]);

    private AppearanceSettings _appearance = new("Light", "Medium", "English", false);

    public Task<UserProfile> GetProfileAsync() => Task.FromResult(_profile);

    public Task SaveProfileAsync(UserProfile profile)
    {
        _profile = profile;
        return Task.CompletedTask;
    }

    public Task<NotificationPrefs> GetNotificationPrefsAsync() => Task.FromResult(_notificationPrefs);

    public Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        _notificationPrefs = prefs;
        return Task.CompletedTask;
    }

    public Task<SecuritySettings> GetSecuritySettingsAsync() => Task.FromResult(_security);

    public Task ChangePasswordAsync(string currentPassword, string newPassword)
    {
        _security = _security with { LastPasswordChange = DateTime.UtcNow };
        return Task.CompletedTask;
    }

    public Task RevokeSessionAsync(string sessionId)
    {
        var updated = _security.Sessions.Where(s => s.Id != sessionId).ToList();
        _security = _security with { Sessions = updated };
        return Task.CompletedTask;
    }

    public Task<AppearanceSettings> GetAppearanceAsync() => Task.FromResult(_appearance);

    public Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        _appearance = settings;
        return Task.CompletedTask;
    }
}

