@namespace sv_29fb1a693b474e1db6cd503ab98e3853.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="section-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_29fb1a693b474e1db6cd503ab98e3853.Components.Pages.Settings
@using sv_29fb1a693b474e1db6cd503ab98e3853.Models

<div class="settings-section">
    <h3>Profile</h3>
    <p class="text-muted">Manage your personal information</p>
    <hr />

    <div class="profile-layout">
        <div class="avatar-area">
            <div class="avatar-preview">
                <img src="@AvatarUrl" alt="Avatar" class="avatar-img" />
            </div>
            <div class="mt-2">
                <label class="form-label fw-semibold">Avatar URL</label>
                <input type="text" class="form-control form-control-sm" value="@AvatarUrl"
                       @oninput="e => AvatarUrl = e.Value?.ToString() ?? string.Empty" />
            </div>
        </div>

        <div class="profile-fields">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" value="@DisplayName"
                       @oninput="e => DisplayName = e.Value?.ToString() ?? string.Empty" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" value="@Email"
                       @oninput="e => Email = e.Value?.ToString() ?? string.Empty" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @oninput="e => Bio = e.Value?.ToString() ?? string.Empty">@Bio</textarea>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="Save" disabled="@IsSaving">
            @(IsSaving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>

    @if (ShowSuccess)
    {
        <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
            ✅ Profile saved successfully!
        </div>
    }
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private bool IsSaving;
    private bool ShowSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            LoadFromProfile(Profile);
            _initialized = true;
        }
    }

    private bool _initialized;

    private void LoadFromProfile(UserProfile p)
    {
        DisplayName = p.DisplayName;
        Email = p.Email;
        AvatarUrl = p.AvatarUrl;
        Bio = p.Bio;
    }

    private async Task Save()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        ShowSuccess = false;
    }
}

@namespace sv_29fb1a693b474e1db6cd503ab98e3853.Components.Pages.Settings
@using sv_29fb1a693b474e1db6cd503ab98e3853.Models

<div class="settings-section">
    <h3>Notifications</h3>
    <p class="text-muted">Choose how you want to be notified</p>
    <hr />

    <div class="mb-4">
        <h5>General</h5>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@EmailNotifications"
                   @onchange="e => EmailNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="emailNotif">
                <strong>Email Notifications</strong>
                <div class="text-muted small">Receive notifications via email</div>
            </label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@PushNotifications"
                   @onchange="e => PushNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="pushNotif">
                <strong>Push Notifications</strong>
                <div class="text-muted small">Receive push notifications in browser</div>
            </label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@WeeklyDigest"
                   @onchange="e => WeeklyDigest = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="weeklyDigest">
                <strong>Weekly Digest</strong>
                <div class="text-muted small">Get a summary of activity every week</div>
            </label>
        </div>
    </div>

    <div class="mb-4">
        <h5>Muted Channels</h5>
        <p class="text-muted small">Uncheck channels you want to receive notifications from</p>

        @if (AllChannels.Count > 0)
        {
            <div class="channel-list">
                @foreach (var channel in AllChannels)
                {
                    var isMuted = MutedChannels.Contains(channel);
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@isMuted"
                               @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="Save" disabled="@IsSaving">
        @(IsSaving ? "Saving..." : "Save Preferences")
    </button>

    @if (ShowSuccess)
    {
        <div class="alert alert-success mt-3">✅ Notification preferences saved!</div>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];
    private List<string> AllChannels = [];
    private bool IsSaving;
    private bool ShowSuccess;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            AllChannels = [.. Prefs.MutedChannels];
            MutedChannels = [.. Prefs.MutedChannels];
            _initialized = true;
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_29fb1a693b474e1db6cd503ab98e3853.Components.Pages.Settings
@using sv_29fb1a693b474e1db6cd503ab98e3853.Models

<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage your account security</p>
    <hr />

    @* Change Password Panel *@
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer" @onclick="() => PasswordPanelOpen = !PasswordPanelOpen">
            <strong>Change Password</strong>
            <span>@(PasswordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (PasswordPanelOpen)
        {
            <div class="card-body">
                @if (Settings?.LastPasswordChange is not null)
                {
                    <p class="text-muted small">Last changed: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
                }
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="CurrentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="NewPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="ConfirmPassword" />
                </div>

                @if (!string.IsNullOrEmpty(PasswordError))
                {
                    <div class="alert alert-danger">@PasswordError</div>
                }
                @if (PasswordSuccess)
                {
                    <div class="alert alert-success">✅ Password updated successfully!</div>
                }

                <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@IsChangingPassword">
                    @(IsChangingPassword ? "Updating..." : "Update Password")
                </button>
            </div>
        }
    </div>

    @* Two-Factor Authentication *@
    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <strong>Two-Factor Authentication</strong>
                <div class="mt-1">
                    @if (TwoFactorEnabled)
                    {
                        <span class="badge bg-success">Enabled</span>
                    }
                    else
                    {
                        <span class="badge bg-warning text-dark">Disabled</span>
                    }
                </div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" checked="@TwoFactorEnabled"
                       @onchange="e => TwoFactorEnabled = (bool)(e.Value ?? false)" />
            </div>
        </div>
    </div>

    @* Active Sessions *@
    <div class="card mb-4">
        <div class="card-header"><strong>Active Sessions</strong></div>
        <div class="card-body p-0">
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead class="table-light">
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (Sessions is not null)
                        {
                            @foreach (var session in Sessions)
                            {
                                var isCurrent = session == Sessions.FirstOrDefault();
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info ms-2">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>
        </div>
    </div>

    @* Revoke Confirmation Dialog *@
    @if (SessionToRevoke is not null)
    {
        <div class="modal-backdrop show"></div>
        <div class="modal d-block" tabindex="-1">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke this session?</p>
                        <p><strong>@SessionToRevoke.Device</strong> — @SessionToRevoke.Location</p>
                        <p class="text-muted small">This will immediately sign out this device.</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@IsRevoking">
                            @(IsRevoking ? "Revoking..." : "Revoke Session")
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string currentPassword, string newPassword)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool PasswordPanelOpen;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? PasswordError;
    private bool PasswordSuccess;
    private bool IsChangingPassword;

    private bool TwoFactorEnabled;
    private List<ActiveSession>? Sessions;

    private ActiveSession? SessionToRevoke;
    private bool IsRevoking;

    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            TwoFactorEnabled = Settings.TwoFactorEnabled;
            Sessions = [.. Settings.Sessions];
            _initialized = true;
        }
    }

    private async Task UpdatePassword()
    {
        PasswordError = null;
        PasswordSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword))
        {
            PasswordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(NewPassword) || NewPassword.Length < 8)
        {
            PasswordError = "New password must be at least 8 characters.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            PasswordError = "Passwords do not match.";
            return;
        }

        IsChangingPassword = true;
        await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
        IsChangingPassword = false;
        PasswordSuccess = true;
        CurrentPassword = "";
        NewPassword = "";
        ConfirmPassword = "";
    }

    private void PromptRevoke(ActiveSession session) => SessionToRevoke = session;
    private void CancelRevoke() => SessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (SessionToRevoke is null) return;
        IsRevoking = true;
        var id = SessionToRevoke.Id;
        await OnRevokeSession.InvokeAsync(id);
        Sessions?.RemoveAll(s => s.Id == id);
        SessionToRevoke = null;
        IsRevoking = false;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

