{"file_text": "@namespace sv_29fb1a693b474e1db6cd503ab98e3853.Components.Pages.Settings
@using sv_29fb1a693b474e1db6cd503ab98e3853.Models

<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage your account security</p>
    <hr />

    @* Change Password Panel *@
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer" @onclick="() => PasswordPanelOpen = !PasswordPanelOpen">
            <strong>Change Password</strong>
            <span>@(PasswordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (PasswordPanelOpen)
        {
            <div class="card-body">
                @if (Settings?.LastPasswordChange is not null)
                {
                    <p class="text-muted small">Last changed: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
                }
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="CurrentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="NewPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="ConfirmPassword" />
                </div>

                @if (!string.IsNullOrEmpty(PasswordError))
                {
                    <div class="alert alert-danger">@PasswordError</div>
                }
                @if (PasswordSuccess)
                {
                    <div class="alert alert-success">✅ Password updated successfully!</div>
                }

                <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@IsChangingPassword">
                    @(IsChangingPassword ? "Updating..." : "Update Password")
                </button>
            </div>
        }
    </div>

    @* Two-Factor Authentication *@
    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <strong>Two-Factor Authentication</strong>
                <div class="mt-1">
                    @if (TwoFactorEnabled)
                    {
                        <span class="badge bg-success">Enabled</span>
                    }
                    else
                    {
                        <span class="badge bg-warning text-dark">Disabled</span>
                    }
                </div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" checked="@TwoFactorEnabled"
                       @onchange="e => TwoFactorEnabled = (bool)(e.Value ?? false)" />
            </div>
        </div>
    </div>

    @* Active Sessions *@
    <div class="card mb-4">
        <div class="card-header"><strong>Active Sessions</strong></div>
        <div class="card-body p-0">
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead class="table-light">
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (Sessions is not null)
                        {
                            @foreach (var session in Sessions)
                            {
                                var isCurrent = session == Sessions.FirstOrDefault();
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info ms-2">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>
        </div>
    </div>

    @* Revoke Confirmation Dialog *@
    @if (SessionToRevoke is not null)
    {
        <div class="modal-backdrop show"></div>
        <div class="modal d-block" tabindex="-1">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke this session?</p>
                        <p><strong>@SessionToRevoke.Device</strong> — @SessionToRevoke.Location</p>
                        <p class="text-muted small">This will immediately sign out this device.</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@IsRevoking">
                            @(IsRevoking ? "Revoking..." : "Revoke Session")
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string currentPassword, string newPassword)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool PasswordPanelOpen;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? PasswordError;
    private bool PasswordSuccess;
    private bool IsChangingPassword;

    private bool TwoFactorEnabled;
    private List<ActiveSession>? Sessions;

    private ActiveSession? SessionToRevoke;
    private bool IsRevoking;

    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            TwoFactorEnabled = Settings.TwoFactorEnabled;
            Sessions = [.. Settings.Sessions];
            _initialized = true;
        }
    }

    private async Task UpdatePassword()
    {
        PasswordError = null;
        PasswordSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword))
        {
            PasswordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(NewPassword) || NewPassword.Length < 8)
        {
            PasswordError = "New password must be at least 8 characters.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            PasswordError = "Passwords do not match.";
            return;
        }

        IsChangingPassword = true;
        await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
        IsChangingPassword = false;
        PasswordSuccess = true;
        CurrentPassword = "";
        NewPassword = "";
        ConfirmPassword = "";
    }

    private void PromptRevoke(ActiveSession session) => SessionToRevoke = session;
    private void CancelRevoke() => SessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (SessionToRevoke is null) return;
        IsRevoking = true;
        var id = SessionToRevoke.Id;
        await OnRevokeSession.InvokeAsync(id);
        Sessions?.RemoveAll(s => s.Id == id);
        SessionToRevoke = null;
        IsRevoking = false;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
