@namespace sv_29fb1a693b474e1db6cd503ab98e3853.Components.Pages.Settings
@using sv_29fb1a693b474e1db6cd503ab98e3853.Models

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="text-muted">Customize the look and feel</p>
    <hr />

    <div class="row">
        <div class="col-md-7">
            @* Theme *@
            <div class="mb-4">
                <h5>Theme</h5>
                <div class="d-flex gap-3">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(Theme == theme)"
                                   @onchange="() => Theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            @* Font Size *@
            <div class="mb-4">
                <h5>Font Size</h5>
                <div class="d-flex gap-3">
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(FontSize == size)"
                                   @onchange="() => FontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            @* Language *@
            <div class="mb-4">
                <h5>Language</h5>
                <select class="form-select" style="max-width: 250px"
                        value="@Language" @onchange="e => Language = e.Value?.ToString() ?? Language">
                    <option value="English">English</option>
                    <option value="Spanish">Spanish</option>
                    <option value="French">French</option>
                    <option value="German">German</option>
                    <option value="Japanese">Japanese</option>
                    <option value="Chinese">Chinese</option>
                </select>
            </div>

            @* Compact Mode *@
            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@CompactMode"
                           @onchange="e => CompactMode = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="compactMode">
                        <strong>Compact Mode</strong>
                        <div class="text-muted small">Reduce spacing and padding for a denser layout</div>
                    </label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="Save" disabled="@IsSaving">
                @(IsSaving ? "Saving..." : "Save")
            </button>

            @if (ShowSuccess)
            {
                <div class="alert alert-success mt-3">✅ Appearance settings saved!</div>
            }
        </div>

        @* Live Preview *@
        <div class="col-md-5">
            <div class="preview-panel @GetPreviewThemeClass()" style="@GetPreviewStyle()">
                <h6 class="preview-title">Live Preview</h6>
                <div class="preview-content">
                    <div class="preview-header">
                        <div class="preview-avatar"></div>
                        <div>
                            <div class="preview-name">Jane Doe</div>
                            <div class="preview-meta">Software Engineer</div>
                        </div>
                    </div>
                    <div class="preview-card">
                        <div class="preview-card-title">Dashboard</div>
                        <p class="preview-card-text">This is how your content will look with the selected settings.</p>
                        <button class="preview-btn">Action Button</button>
                    </div>
                    <div class="preview-footer">
                        <span>Theme: @Theme</span> · <span>Font: @FontSize</span> · <span>Lang: @Language</span>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;
    private bool IsSaving;
    private bool ShowSuccess;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
            _initialized = true;
        }
    }

    private string GetPreviewThemeClass() => Theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string GetPreviewStyle()
    {
        var fontSize = FontSize switch
        {
            "Small" => "12px",
            "Large" => "18px",
            _ => "14px"
        };
        var padding = CompactMode ? "8px" : "16px";
        return $"font-size: {fontSize}; --preview-padding: {padding};";
    }

    private async Task Save()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

