@page "/settings"
@namespace sv_29fb1a693b474e1db6cd503ab98e3853.Components.Pages.Settings
@rendermode InteractiveServer
@using sv_29fb1a693b474e1db6cd503ab98e3853.Models
@using sv_29fb1a693b474e1db6cd503ab98e3853.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-page">
    <SettingsSidebar ActiveSection="@activeSection" OnSectionChanged="s => activeSection = s" />

    <div class="settings-content">
        @if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center" style="min-height: 300px">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@profile" OnSave="SaveProfile" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@notificationPrefs" OnSave="SaveNotifications" />
                    break;
                case "Security":
                    <SecuritySection Settings="@securitySettings"
                                     OnChangePassword="ChangePassword"
                                     OnRevokeSession="RevokeSession" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@appearanceSettings" OnSave="SaveAppearance" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string activeSection = "Profile";
    private bool isLoading = true;

    private UserProfile? profile;
    private NotificationPrefs? notificationPrefs;
    private SecuritySettings? securitySettings;
    private AppearanceSettings? appearanceSettings;

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

        profile = profileTask.Result;
        notificationPrefs = notifsTask.Result;
        securitySettings = securityTask.Result;
        appearanceSettings = appearanceTask.Result;

        isLoading = false;
    }

    private async Task SaveProfile(UserProfile updated)
    {
        await SettingsService.SaveProfileAsync(updated);
        profile = updated;
    }

    private async Task SaveNotifications(NotificationPrefs updated)
    {
        await SettingsService.SaveNotificationPrefsAsync(updated);
        notificationPrefs = updated;
    }

    private async Task ChangePassword((string currentPassword, string newPassword) args)
    {
        await SettingsService.ChangePasswordAsync(args.currentPassword, args.newPassword);
        securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
    }

    private async Task SaveAppearance(AppearanceSettings updated)
    {
        await SettingsService.SaveAppearanceAsync(updated);
        appearanceSettings = updated;
    }
}

/* ── Settings Page Layout ── */
.settings-page {
    display: flex;
    gap: 0;
    min-height: calc(100vh - 120px);
    background: #f8f9fa;
    border-radius: 8px;
    overflow: hidden;
    border: 1px solid #dee2e6;
}

/* ── Sidebar ── */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #fff;
    border-right: 1px solid #dee2e6;
    padding: 1.25rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin-bottom: 0.5rem;
    font-weight: 700;
    color: #333;
    border-bottom: 1px solid #eee;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1.25rem;
    color: #555;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    transition: all 0.15s ease;
    border-left: 3px solid transparent;
}

.settings-sidebar .nav-link:hover {
    background: #f0f4ff;
    color: #0d6efd;
}

.settings-sidebar .nav-link.active {
    background: #e8f0fe;
    color: #0d6efd;
    font-weight: 600;
    border-left-color: #0d6efd;
}

.section-icon {
    font-size: 1.1rem;
}

/* ── Content Area ── */
.settings-content {
    flex: 1;
    padding: 2rem;
    background: #fff;
    overflow-y: auto;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
    font-weight: 700;
}

/* ── Profile Section ── */
.profile-layout {
    display: flex;
    gap: 2rem;
}

.avatar-area {
    flex-shrink: 0;
    width: 180px;
    text-align: center;
}

.avatar-preview {
    width: 120px;
    height: 120px;
    margin: 0 auto;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
    background: #f0f0f0;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.profile-fields {
    flex: 1;
}

/* ── Notifications Channel List ── */
.channel-list {
    max-height: 200px;
    overflow-y: auto;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
    background: #fafafa;
}

/* ── Appearance Preview ── */
.preview-panel {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: var(--preview-padding, 16px);
    min-height: 280px;
    transition: all 0.2s ease;
}

.preview-light {
    background: #ffffff;
    color: #333;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
}

.preview-title {
    text-align: center;
    margin-bottom: 1em;
    opacity: 0.6;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-size: 0.75em;
}

.preview-content {
    display: flex;
    flex-direction: column;
    gap: var(--preview-padding, 16px);
}

.preview-header {
    display: flex;
    align-items: center;
    gap: 0.75em;
}

.preview-avatar {
    width: 2.5em;
    height: 2.5em;
    border-radius: 50%;
    flex-shrink: 0;
}

.preview-light .preview-avatar {
    background: #d0d7de;
}

.preview-dark .preview-avatar {
    background: #444;
}

.preview-name {
    font-weight: 600;
}

.preview-meta {
    opacity: 0.6;
    font-size: 0.85em;
}

.preview-card {
    border-radius: 6px;
    padding: var(--preview-padding, 16px);
}

.preview-light .preview-card {
    background: #f6f8fa;
    border: 1px solid #e1e4e8;
}

.preview-dark .preview-card {
    background: #2d2d3f;
    border: 1px solid #3d3d4f;
}

.preview-card-title {
    font-weight: 600;
    margin-bottom: 0.5em;
}

.preview-card-text {
    opacity: 0.7;
    font-size: 0.9em;
    margin-bottom: 0.75em;
}

.preview-btn {
    border: none;
    border-radius: 4px;
    padding: 0.35em 1em;
    font-size: 0.85em;
    cursor: default;
}

.preview-light .preview-btn {
    background: #0d6efd;
    color: #fff;
}

.preview-dark .preview-btn {
    background: #4c8bf5;
    color: #fff;
}

.preview-footer {
    text-align: center;
    font-size: 0.75em;
    opacity: 0.5;
}

/* ── Modal backdrop fix ── */
::deep .modal-backdrop {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    z-index: 1040;
}

::deep .modal {
    z-index: 1050;
}

