.settings-section h3 {
    margin-bottom: 0.25rem;
    font-weight: 700;
}

/* ── Profile Section ── */
.profile-layout {
    display: flex;
    gap: 2rem;
}

.avatar-area {
    flex-shrink: 0;
    width: 180px;
    text-align: center;
}

.avatar-preview {
    width: 120px;
    height: 120px;
    margin: 0 auto;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
    background: #f0f0f0;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.profile-fields {
    flex: 1;
}

/* ── Notifications Channel List ── */
.channel-list {
    max-height: 200px;
    overflow-y: auto;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
    background: #fafafa;
}

/* ── Appearance Preview ── */
.preview-panel {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: var(--preview-padding, 16px);
    min-height: 280px;
    transition: all 0.2s ease;
}

.preview-light {
    background: #ffffff;
    color: #333;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
}

.preview-title {
    text-align: center;
    margin-bottom: 1em;
    opacity: 0.6;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-size: 0.75em;
}

.preview-content {
    display: flex;
    flex-direction: column;
    gap: var(--preview-padding, 16px);
}

.preview-header {
    display: flex;
    align-items: center;
    gap: 0.75em;
}

.preview-avatar {
    width: 2.5em;
    height: 2.5em;
    border-radius: 50%;
    flex-shrink: 0;
}

.preview-light .preview-avatar {
    background: #d0d7de;
}

.preview-dark .preview-avatar {
    background: #444;
}

.preview-name {
    font-weight: 600;
}

.preview-meta {
    opacity: 0.6;
    font-size: 0.85em;
}

.preview-card {
    border-radius: 6px;
    padding: var(--preview-padding, 16px);
}

.preview-light .preview-card {
    background: #f6f8fa;
    border: 1px solid #e1e4e8;
}

.preview-dark .preview-card {
    background: #2d2d3f;
    border: 1px solid #3d3d4f;
}

.preview-card-title {
    font-weight: 600;
    margin-bottom: 0.5em;
}

.preview-card-text {
    opacity: 0.7;
    font-size: 0.9em;
    margin-bottom: 0.75em;
}

.preview-btn {
    border: none;
    border-radius: 4px;
    padding: 0.35em 1em;
    font-size: 0.85em;
    cursor: default;
}

.preview-light .preview-btn {
    background: #0d6efd;
    color: #fff;
}

.preview-dark .preview-btn {
    background: #4c8bf5;
    color: #fff;
}

.preview-footer {
    text-align: center;
    font-size: 0.75em;
    opacity: 0.5;
}

/* ── Modal backdrop fix ── */
::deep .modal-backdrop {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    z-index: 1040;
}

::deep .modal {
    z-index: 1050;
}
